import React from "react";

interface TooltipProps {
  imageUrl: string;
}

const Tooltip: React.FC<TooltipProps> = ({ imageUrl }) => {
  return (
    <div className="tooltip">
      <img src={imageUrl} alt="large" />
    </div>
  );
};

export default Tooltip;
